import{_ as a,c as e,a as i,o as n}from"./app-CEcM0piI.js";const t={};function r(d,s){return n(),e("div",null,s[0]||(s[0]=[i(`<h3 id="字符串长度" tabindex="-1"><a class="header-anchor" href="#字符串长度"><span>字符串长度</span></a></h3><p>#pragma 指令的作用是:用于指定计算机或操作系统特定的编译器功能 #pragma warning(disable:4996)在文件开始处写上这句话，即告诉编译器忽略 4996警告，strcpy、scanf.等一些不安全的标准c库函数在 vs 中可以用了</p><p>关于处理字符串的函数都需要导入string.h库</p><p>函数定义:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>size_t strlen(const char* s);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>函数功能: 测字符指针 s 指向的字符串中字符的个数，不包括\\0</p><p>返回值:字符串中字符个数</p><h3 id="字符串拷贝" tabindex="-1"><a class="header-anchor" href="#字符串拷贝"><span>字符串拷贝</span></a></h3><h4 id="strcpy" tabindex="-1"><a class="header-anchor" href="#strcpy"><span>strcpy</span></a></h4><p>函数的声明: char * strcpy(char* dest,const char* src);</p><p>拷贝src 指向的字符串到 dest 指针指向的内存中，\\0也会拷贝</p><p>函数的返回值:目的内存的地址</p><p>在使用此函数的时候，必须保证 dest 指向的内存空间足够大，否则会出现内存污染</p><h4 id="内存污染" tabindex="-1"><a class="header-anchor" href="#内存污染"><span>内存污染</span></a></h4><p>如果需要使用的空间不够大，就会占据后面已经使用过的空间存储新数据，而原本存在这个位置的数据被修改</p><h4 id="strncpy" tabindex="-1"><a class="header-anchor" href="#strncpy"><span>strncpy</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char * strncpy(char * dest, const char * src, size tn);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将 src 指向的字符串前n 个字节，拷贝到 dest 指向的内存中 返回值:目的内存的首地址</p><p>strncpy 不拷贝\\0</p><p>如果 n 大于 src 指向的字符串中的字符个数，则在 dest 后面填充 n-strlen(src)个\\0</p><h3 id="字符串追加" tabindex="-1"><a class="header-anchor" href="#字符串追加"><span>字符串追加</span></a></h3><h4 id="strcat" tabindex="-1"><a class="header-anchor" href="#strcat"><span>strcat</span></a></h4><p>函数声明:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char* strcat(char * dest, const char * src);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>strcat 函数追加 src 字符串到 dest 指向的字符串的后面。追加的时候会追加\\0 保证 dest 指向的内存空间足够大。</p><h4 id="strncat" tabindex="-1"><a class="header-anchor" href="#strncat"><span>strncat</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char* strncat(char * dest, const char * src,size tn);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>追加 src 指向的字符串的前n个字符，到 dest 指向的字符串的后面。 如果n 大于 src 的字符个数，则只将 src 字符串追加到 dest 指向的字符串的后面追加的时候会追加\\0</p><h3 id="字符串比较" tabindex="-1"><a class="header-anchor" href="#字符串比较"><span>字符串比较</span></a></h3><h4 id="strcmp" tabindex="-1"><a class="header-anchor" href="#strcmp"><span>strcmp</span></a></h4><p>函数声明:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int strcmp(const char * s1, const char * s2);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>比较 s1 和 s2 指向的字符串的大小 比较的方法:逐个字符去比较 ascII 码</p><p>如果 s1 指向的字符串大于 s2 指向的字符串返回1 如果 s1 指向的字符串小于 s2 指向的字符串返回-1 如果相等的话返回 0</p><h4 id="strncmp" tabindex="-1"><a class="header-anchor" href="#strncmp"><span>strncmp</span></a></h4><p>函数声明：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int strncmp(const char * s1, const char * s2, size t n);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>函数说明: 比较 s1 和 s2 指向的字符串中的前 n 个字符</p><h3 id="字符串查找" tabindex="-1"><a class="header-anchor" href="#字符串查找"><span>字符串查找</span></a></h3><h4 id="strchar" tabindex="-1"><a class="header-anchor" href="#strchar"><span>strchar</span></a></h4><p>函数声明: char strchr(const char * s,int c);</p><p>在字符指针 s 指向的字符串中，找 ascii 码为 c的字符注意，是首次匹配，如果 s 指向的字符串中有多个 ASCII为 的字符，则找的是第1个字符</p><p>返回值: 找到了返回找到的字符的地址 找不到返回 NULL</p><h4 id="strrchar" tabindex="-1"><a class="header-anchor" href="#strrchar"><span>strrchar</span></a></h4><p>函数声明: char * strchr(const char * s, int c);</p><p>末次匹配 在 s 指向的字符串中，找最后一次出现的 ASCII为c的字符</p><p>返回值: 末次匹配的字符的地址。</p><h3 id="字符串匹配" tabindex="-1"><a class="header-anchor" href="#字符串匹配"><span>字符串匹配</span></a></h3><h4 id="strstr" tabindex="-1"><a class="header-anchor" href="#strstr"><span>strstr</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char * strstr(const char * haystack, const char * needle);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在 haystack 指向的字符串中查找 needle 指向的字符串，也是首次匹配</p><p>返回值: 找到了找到的字符串的首地址 没找到返回 NULL</p><h3 id="空间设定" tabindex="-1"><a class="header-anchor" href="#空间设定"><span>空间设定</span></a></h3><p>函数声明:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void* memset(void * ptr,int value,size_t num);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将 ptr 指向的内存空间的num个字节全部赋值为 value</p><p>ptr: 指向任意类型的指针，即指向我们需要修改的内存 value:给 ptr 指向的内存空间的赋的值。 num:确定将ptr 所指的内存中的num 个字节全都用value代替</p><p>返回目的内存的首地址，即 ptr 的值</p><h3 id="字符串和数值的转换" tabindex="-1"><a class="header-anchor" href="#字符串和数值的转换"><span>字符串和数值的转换</span></a></h3><h4 id="atoi字符串转整数" tabindex="-1"><a class="header-anchor" href="#atoi字符串转整数"><span>atoi字符串转整数</span></a></h4><p>函数的声明:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int atoi(const char * nptr);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将nptr 指向的字符串转换成整数，返回转换后的整数，此值由将输入字符作为数字解析而生成。 如果该输入无法转换为该类型的值，则 atoi的返回值为 0</p><h4 id="atol字符串转长整型" tabindex="-1"><a class="header-anchor" href="#atol字符串转长整型"><span>atol字符串转长整型</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>long atol(const char* nptr);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="atof字符串转浮点型" tabindex="-1"><a class="header-anchor" href="#atof字符串转浮点型"><span>atof字符串转浮点型</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>double atof(const char* nptr);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="字符串切割" tabindex="-1"><a class="header-anchor" href="#字符串切割"><span>字符串切割</span></a></h3><h4 id="strtok" tabindex="-1"><a class="header-anchor" href="#strtok"><span>strtok</span></a></h4><p>函数声明:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char * strtok(char * str, const char * delim);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>按照 delim 指向的字符串中的字符，切割 str 指向的字符串</p><p>按照 delim 指向的字符串中的字符，切割 str 指向的字符串。其实就是在 str 指向的字符串中发现了 delim 字符串中的字符，就将其变成\\0调用一次 strtok 只切割一次，切割一次之后，再去切割的时候 strtok 的第一个参数传 NULL，strtok函数具有记忆功能传null意思是接着上次切割的位置继续切。如果传原来的str，原本第一个delim中的字符被修改为\\0，函数遇到\\0会以为到达了字符串末端就不会再往后运行了。</p><p>如果 str 字符串中出现了连续的几个 delim 中的字符，则只将第一个字符变成\\0</p><h3 id="格式化字符串操作" tabindex="-1"><a class="header-anchor" href="#格式化字符串操作"><span>格式化字符串操作</span></a></h3><h2 id="sprintf" tabindex="-1"><a class="header-anchor" href="#sprintf"><span>sprintf</span></a></h2><p>int sprintf(char * buf, const char * format,……); 输出到 buf指定的内存区域。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>char buf[201;</span></span>
<span class="line"><span>sprintf(buf&quot;d:%d:%d&quot;,2013,10.1);</span></span>
<span class="line"><span>printf(&quot;buf=%s\\n&quot;buf);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="sscanf" tabindex="-1"><a class="header-anchor" href="#sscanf"><span>sscanf</span></a></h2><p>int sscanf(const char * buf,const char * format,···); 从 buf指定的内存区域中读入信息</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int a, b,c;</span></span>
<span class="line"><span>sscanf(&quot;2013:10:1&quot;,&quot;%d:%d:%d&quot;&amp;a,&amp;b,&amp;c);</span></span>
<span class="line"><span>printf(&quot;%d,%d,%d\\n&quot;,a,b.c);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="高级用法" tabindex="-1"><a class="header-anchor" href="#高级用法"><span>高级用法</span></a></h3><h4 id="_1、跳过数据-s-或-d" tabindex="-1"><a class="header-anchor" href="#_1、跳过数据-s-或-d"><span>1、跳过数据:%* s 或%* d</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>sscanf(&quot;1234 5678&quot;,&quot;%*d %s&quot;,buf);//跳过 1234 ,然后隔一个空格获取字符串</span></span>
<span class="line"><span>printf(&quot;%s\\n&quot;, buf);//5678</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sscanf(&quot;1234 5678&quot;,&quot;%s&quot;,buf);</span></span>
<span class="line"><span>printf(&quot;%s\\n,buf&quot;);//1234</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>%s是获取字符串，%* s是跳过字符串，%d是获取整数%* d是跳过整数,中间加一个空格是跳过空格 sscanf和scanf一样遇到空格时就停止获取</p><h4 id="_2、读指定宽度的数据-width-s" tabindex="-1"><a class="header-anchor" href="#_2、读指定宽度的数据-width-s"><span>2、读指定宽度的数据:%[width]s</span></a></h4><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>sscanf(&quot;12345678&quot;,&quot;%4s&quot;,buf);//获取前四个字符</span></span>
<span class="line"><span>print(&quot;%s\\n&quot;,buf)//1234</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3、支持集合操作-只支持获取字符串" tabindex="-1"><a class="header-anchor" href="#_3、支持集合操作-只支持获取字符串"><span>3、支持集合操作:只支持获取字符串</span></a></h2><p>%[a-z] 表示匹配 a到z 中任意字符(尽可能多的匹配)直到遇到不在此范围内的字符（或空格）就终止</p><p>%[aBc] 匹配a、B、c中一员 %[ ^aFc] 匹配非 aFc的任意字符 %[ ^a-z]表示读取除 a-z 以外的所有字符</p>`,90)]))}const c=a(t,[["render",r]]),l=JSON.parse('{"path":"/cpp/c/5/","title":"5 字符串处理函数","lang":"zh-CN","frontmatter":{"title":"5 字符串处理函数","createTime":"2025/04/05 12:12:26","permalink":"/cpp/c/5/"},"readingTime":{"minutes":5.35,"words":1606},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/C/5 字符串处理函数.md","headers":[]}');export{c as comp,l as data};
